(function(){'use strict';const API_ENDPOINTS ={LOGOUT:'/api/logout',REGENERATE_WEEK:'/api/regenerate-week',DELETE_SCHEDULE:'/api/delete-schedule'};class DashboardActions{async logout(){try{await fetch(API_ENDPOINTS.LOGOUT,{method:'POST'});window.location.href = '/';}catch(error){console.error('Logout error:',error);window.location.href = '/';}}async generateSchedule(){const weekSelector = document.getElementById('weekSelector');if(!weekSelector){console.error('Week selector not found');return;}const weekStart = weekSelector.value;if(!weekStart){this.showAlert('Выберите неделю для генерации');return;}if(!confirm(`Сгенерировать расписание на неделю с ${weekStart}?`)){return;}this.showLoading('Генерация расписания...');try{const response = await fetch(API_ENDPOINTS.REGENERATE_WEEK,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({week_start_date:weekStart})});const data = await response.json();this.hideLoading();if(data.success){this.showAlert(data.message,'success');setTimeout(()=> window.location.reload(),1500);}else{this.showAlert('Ошибка:' + data.message,'error');}}catch(error){console.error('Generate error:',error);this.hideLoading();this.showAlert('Ошибка соединения с сервером','error');}}async deleteSchedule(){if(!confirm('Вы уверены,что хотите удалить ВСЁ расписание? Это действие необратимо!')){return;}if(!confirm('Последнее предупреждение! Удалить всё расписание?')){return;}this.showLoading('Удаление расписания...');try{const response = await fetch(API_ENDPOINTS.DELETE_SCHEDULE,{method:'DELETE'});const data = await response.json();this.hideLoading();if(data.success){this.showAlert(data.message,'success');setTimeout(()=> window.location.reload(),1500);}else{this.showAlert('Ошибка:' + data.message,'error');}}catch(error){console.error('Delete error:',error);this.hideLoading();this.showAlert('Ошибка соединения с сервером','error');}}showAlert(message,type = 'info'){alert(message);}showLoading(message){const overlay = document.createElement('div');overlay.id = 'loadingOverlay';overlay.style.cssText = ` position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);display:flex;align-items:center;justify-content:center;z-index:9999;`;const content = document.createElement('div');content.style.cssText = ` background:white;padding:30px;border-radius:10px;text-align:center;color:#333;`;content.innerHTML = ` <div class="spinner"></div> <p style="margin-top:15px;font-size:1.1em;">${message}</p> `;overlay.appendChild(content);document.body.appendChild(overlay);}hideLoading(){const overlay = document.getElementById('loadingOverlay');if(overlay){overlay.remove();}}}window.dashboardActions = new DashboardActions();window.logout = function(){return window.dashboardActions.logout();};window.generateSchedule = function(){return window.dashboardActions.generateSchedule();};window.deleteSchedule = function(){return window.dashboardActions.deleteSchedule();};})();